?php
$connect = new mysqli(localhost, root, , chdidong);

$sql_status = SELECT * FROM trangthaidonhang;
$result_status = $connect-query($sql_status);

$statuses = [];
while ($row_status = $result_status-fetch_assoc()) {
    $statuses[] = $row_status[STATUS];
}

$idTK = $_SESSION[id] ?? 0;
if ($idTK == 0) {
    die(Bạn chưa đăng nhập.);
}

$sql = SELECT h.idHD, h.NGAYMUA, h.TRANGTHAI, tdh.STATUS AS TEN_TRANGTHAI, tdh.idSTATUS,
               h.THANHTIEN, h.idVC, h.diachi,
               c.idSP, c.SOLUONG, 
               s.TENSP, s.GIA, s.IMG, s.DISCOUNT,
               v.GIAVANCHUYEN,
               k.GIATRI,
               t.sdt, t.hoten
        FROM donhang h
        JOIN chitiethoadon c ON h.idHD = c.idHD
        JOIN sanpham s ON c.idSP = s.idSP
        JOIN dvvanchuyen v ON h.idVC = v.idVC
        JOIN khuyenmai k ON h.MAKHUYENMAI = k.MAKHUYENMAI
        JOIN taikhoan t ON h.idTK = t.idTK
        JOIN trangthaidonhang tdh ON h.TRANGTHAI = tdh.idSTATUS  
        WHERE h.idTK = ?
        ORDER BY h.idHD DESC;

$stmt = $connect-prepare($sql);
$stmt-bind_param(i, $idTK);
$stmt-execute();
$result = $stmt-get_result();

$orders = [];

while ($row = $result-fetch_assoc()) {
    $idHD = $row[idHD];

    // Gom nhóm các đơn hàng
    if (!isset($orders[$idHD])) {
        $orders[$idHD] = [
            info = [
                idHD = $row[idHD],
                NGAYMUA = $row[NGAYMUA],
                TRANGTHAI_ID = $row[idSTATUS],   // Lưu số trạng thái (1, 2, 3, 4)
                TRANGTHAI_TEN = $row[TEN_TRANGTHAI],  // Lưu tên trạng thái (Chờ xác nhận, Đang giao,...) 
                THANHTIEN = $row[THANHTIEN],
                idVC = $row[idVC],
                GIAVANCHUYEN = $row[GIAVANCHUYEN],
                GIATRI = $row[GIATRI],
                DISCOUNT = $row[DISCOUNT],
                diachi = $row[diachi],
                sdt = $row[sdt],    // Lấy số điện thoại
                hoten = $row[hoten],
            ],
            items = []
        ];
    }

    // Thêm từng sản phẩm vào đơn hàng
    $orders[$idHD][items][] = [
        idSP = $row[idSP],
        TENSP = $row[TENSP],
        SOLUONG = $row[SOLUONG],
        GIA = $row[GIA],
        IMG = $row[IMG]
    ];
}

$stmt-close();
?

